const bizCats={in:[['affiliate','Affiliate'],['jualan','Penjualan'],['refund','Refund'],['lain','Lainnya']],out:[['supplier','Supplier'],['ads','Iklan/Ads'],['pack','Packaging'],['ship','Ongkir'],['fee','Fee platform'],['tools','Tools'],['lain','Lainnya']]};
const def={theme:'night',privacy:false,proMode:false,tx:[],biz:[],products:[],subs:[],snapshots:[],budget:{},learn:{},patterns:{},rules:[],goals:[],accounts:[{id:'cash',name:'Cash',start:0},{id:'bank',name:'Bank',start:0},{id:'ewallet',name:'E-Wallet',start:0},{id:'bisnis',name:'Kas Bisnis',start:0}],lastBackup:'',lastUndo:null,month:new Date().toISOString().slice(0,7)};
