function load(){try{let old=JSON.parse(localStorage.getItem(KEY)||'null'); if(old) return {...def,...old}; let keys=['budget_pro_budgetku_bisnisku_v1','budget_pro_focuscomplete_v1']; for(const k of keys){let v=JSON.parse(localStorage.getItem(k)||'null'); if(v) return {...def,...v,tx:v.tx||v.transactions||[],biz:v.biz||[],products:v.products||[],subs:v.subs||[],snapshots:v.snapshots||[],budget:v.budget||v.budgets||{}}}}catch(e){} return JSON.parse(JSON.stringify(def))}
