function rawMoney(n){return 'Rp '+Math.round(Number(n||0)).toLocaleString('id-ID')}
function money(n){return state.privacy?'Rp••••':rawMoney(n)}
function compact(n){n=Number(n||0); if(n>=1000000) return (Math.round(n/100000)/10).toString().replace('.',',')+'jt'; if(n>=1000)return Math.round(n/1000)+'rb'; return String(n)}
function num(v){
  let raw=String(v||'').toLowerCase().trim();
  if(!raw)return 0;
  raw=raw.replace(/rupiah/g,'').replace(/rp\s*/g,'').replace(/\s+/g,'');
  let multiplier=1;
  const suffixes=[['juta',1000000],['jt',1000000],['million',1000000],['m',1000000],['ribu',1000],['rb',1000],['k',1000]];
  for(const [suf,mul] of suffixes){
    if(raw.endsWith(suf)){
      multiplier=mul;
      raw=raw.slice(0,-suf.length);
      break;
    }
  }
  raw=raw.replace(/[^0-9.,]/g,'');
  if(!raw)return 0;
  function parseWithSuffix(x){
    const dotCount=(x.match(/\./g)||[]).length;
    const commaCount=(x.match(/,/g)||[]).length;
    if(dotCount+commaCount===0)return parseFloat(x);
    if(dotCount+commaCount===1)return parseFloat(x.replace(',','.'));
    const lastDot=x.lastIndexOf('.'), lastComma=x.lastIndexOf(',');
    const dec=lastDot>lastComma?'.':',';
    const thou=dec==='.'?',':'.';
    return parseFloat(x.split(thou).join('').replace(dec,'.'));
  }
  function parsePlain(x){
    const dot=x.includes('.'), comma=x.includes(',');
    if(dot&&comma){
      const lastDot=x.lastIndexOf('.'), lastComma=x.lastIndexOf(',');
      const dec=lastDot>lastComma?'.':',';
      const thou=dec==='.'?',':'.';
      return parseFloat(x.split(thou).join('').replace(dec,'.'));
    }
    const sep=dot?'.':(comma?',':'');
    if(!sep)return parseFloat(x);
    const parts=x.split(sep).filter(Boolean);
    if(parts.length>2)return parseFloat(parts.join(''));
    const last=parts[parts.length-1]||'';
    if(last.length===3)return parseFloat(parts.join(''));
    if(last.length>0&&last.length<=2)return parseFloat(parts[0]+last.padEnd(3,'0'));
    return parseFloat(parts.join(''));
  }
  const base=multiplier>1?parseWithSuffix(raw):parsePlain(raw);
  return isFinite(base)?Math.round(base*multiplier):0;
}
function today(){return new Date().toISOString().slice(0,10)}
function thisMonth(a){return (a.date||'').slice(0,7)===state.month}
function isBizText(low){return /ads|iklan|supplier|marketplace|packing|packaging|ongkir|affiliate|komisi|jualan|reseller|modal|hpp|fee platform|tiktok|shopee affiliate/.test(low)}
function txDateAmount(date,type='expense'){return state.tx.filter(t=>(t.date||'')===date&&t.type===type).reduce((a,t)=>a+(+t.amount||0),0)}
function weekExpense(){let now=new Date(),start=new Date(now); start.setDate(now.getDate()-now.getDay()+1); start.setHours(0,0,0,0); return state.tx.filter(t=>t.type==='expense'&&new Date((t.date||today())+'T00:00:00')>=start).reduce((a,t)=>a+(+t.amount||0),0)}
function saveBizTx(desc, amount, dir){let low=(desc||'').toLowerCase(); let type=dir||(/affiliate|komisi|jualan|penjualan|refund|masuk/.test(low)?'in':'out'); let cat=/supplier|modal|hpp/.test(low)?'supplier':/ads|iklan|tiktok|meta|fb/.test(low)?'ads':/pack|packing|kemasan/.test(low)?'pack':/ongkir|kirim/.test(low)?'ship':/fee|marketplace|admin/.test(low)?'fee':/tool|canva|domain|hosting/.test(low)?'tools':(/affiliate|komisi/.test(low)?'affiliate':(type==='in'?'jualan':'lain')); state.biz.unshift({id:Date.now().toString(36),date:today(),type,cat,amount,desc:desc||'bisnis'});}
function snapshotLocal(){try{let day=today(); let last=(state.snapshots||[])[0]; if(last&&last.day===day)return; let copy={...state,snapshots:[]}; state.snapshots=[{day,createdAt:new Date().toISOString(),state:copy}].concat(state.snapshots||[]).slice(0,10)}catch(e){}}
function restoreSnapshot(){let s=(state.snapshots||[])[0]; if(!s)return toast('Belum ada snapshot'); if(!confirm('Pulihkan snapshot terakhir?'))return; state={...def,...s.state,snapshots:state.snapshots||[]}; localStorage.setItem(KEY,JSON.stringify(state)); render(); toast('Snapshot dipulihkan')}
function isSubText(low){return /netflix|spotify|internet|wifi|domain|hosting|canva|langganan|subscription|server|aplikasi|tools|bpjs|listrik|pdam|pulsa/.test(low)}
function detectSubscription(tx){let low=(tx.desc||'').toLowerCase(); if(tx.type!=='expense'||!isSubText(low))return; let key=(low.match(/netflix|spotify|internet|wifi|domain|hosting|canva|bpjs|listrik|pdam|pulsa|tools|aplikasi/)||[low.split(' ')[0]||'rutin'])[0]; state.subs=state.subs||[]; let old=state.subs.find(x=>x.key===key); if(old){old.amount=tx.amount;old.lastDate=tx.date;old.count=(old.count||1)+1}else state.subs.unshift({id:Date.now().toString(36),key,name:key.charAt(0).toUpperCase()+key.slice(1),amount:tx.amount,lastDate:tx.date,count:1}); state.subs=state.subs.slice(0,20)}
function addSplitRow(catId='makan',amount='',desc=''){let wrap=document.createElement('div'); wrap.className='item split-row'; wrap.innerHTML=`<div class="grid2"><select class="split-cat">${cats.filter(c=>c.type==='expense').map(c=>`<option value="${c.id}" ${c.id===catId?'selected':''}>${c.icon} ${c.name}</option>`).join('')}</select><input class="split-amount" placeholder="25rb" value="${amount}"></div><input class="split-desc" style="margin-top:8px" placeholder="catatan" value="${desc}"><button class="chip split-remove" style="margin-top:8px">Hapus</button>`; $('#splitRows').appendChild(wrap)}
function openSplitSheet(){let p=parseQuick(); $('#splitRows').innerHTML=''; let half=Math.round((p.amount||0)/2); addSplitRow(p.cat,p.amount?compact(half):'',p.desc); addSplitRow('belanja',p.amount?compact((p.amount||0)-half):'','barang lain'); openSheet('splitSheet')}
function saveSplit(){let rows=$$('.split-row'), total=0, made=0; rows.forEach(r=>{let amount=num(r.querySelector('.split-amount').value); if(!amount)return; let categoryId=r.querySelector('.split-cat').value, desc=r.querySelector('.split-desc').value||cat(categoryId).name; let tx={id:Date.now().toString(36)+Math.random().toString(36).slice(2,5),date:today(),type:'expense',categoryId,amount,method:$('#qMethod').value||'Cash',desc}; state.tx.unshift(tx); rememberPattern(desc,categoryId,amount,tx.method); detectSubscription(tx); total+=amount; made++}); if(!made)return toast('Isi nominal split dulu'); state.lastUndo=null; closeSheet('splitSheet'); $('#quickText').value=''; save('Split tersimpan '+money(total))}
function productProfit(p){return ((+p.price||0)-(+p.cost||0)-(+p.fee||0))*(+p.qty||1)}
function saveProduct(){let name=$('#prodName').value.trim(); if(!name)return toast('Nama produk kosong'); let cost=num($('#prodCost').value), price=num($('#prodPrice').value), fee=num($('#prodFee').value), qty=Math.max(1,Math.round(num($('#prodQty').value)||1)), stock=Math.max(0,Math.round(num($('#prodStock').value)||0)); if(!price)return toast('Harga jual belum kebaca'); state.products=state.products||[]; state.products.unshift({id:Date.now().toString(36),name,cost,price,fee,qty,stock,date:today()}); closeSheet('productSheet'); save('Produk disimpan')}
function renderProducts(){let rows=(state.products||[]).slice(0,8); let total=rows.reduce((a,p)=>a+productProfit(p),0); let html=rows.length?rows.map(p=>`<div class="item"><div class="row"><h3>📦 ${p.name}</h3><b>${money(productProfit(p))}</b></div><p>Modal ${money(p.cost)} · jual ${money(p.price)} · fee ${money(p.fee)} · qty ${p.qty} · stok ${p.stock||0}</p></div>`).join(''):'<p class="helper">Belum ada produk. Tambah produk untuk lihat profit bersih.</p>'; if($('#productMini'))$('#productMini').innerHTML=rows[0]?`<div class="item"><div class="row"><h3>Produk paling cuan</h3><b>${money(Math.max(...rows.map(productProfit),0))}</b></div><p>${rows[0].name} · stok ${rows[0].stock||0} · total profit ${money(total)}</p></div>`:'<p class="helper" style="margin-top:10px">Tambah produk untuk hitung profit.</p>'; if($('#productDetail'))$('#productDetail').innerHTML=html}
function renderSubs(){let rows=(state.subs||[]).slice(0,10); let html=rows.length?rows.map(x=>`<div class="item"><div class="row"><h3>🔁 ${x.name}</h3><b>${money(x.amount)}</b></div><p>Terakhir ${x.lastDate||'-'} · terdeteksi ${x.count||1}x</p></div>`).join(''):'<p class="helper">Belum ada langganan terdeteksi.</p>'; if($('#subsDetail'))$('#subsDetail').innerHTML=html; return rows}
function tomorrowForecast(){let s=sums(); let d=new Date(); let leftDays=Math.max(1,30-d.getDate()); let safe=s.budget?Math.max(0,(s.budget-s.expense)/leftDays):0; let sub=(state.subs||[]).slice(0,3).reduce((a,b)=>a+(+b.amount||0)/30,0); return {safe,sub,net:Math.max(0,safe-sub)}}
function behaviorScore(){let s=sums(), no=countNoSpendDays(), score=60; if(s.budget&&s.used<80)score+=18; if(s.net>0)score+=12; if(no>=4)score+=10; if(s.used>100)score-=25; return Math.max(0,Math.min(100,Math.round(score)))}


function daysLeft(){let mi=monthInfo(); return Math.max(1,mi.dim-mi.day+1)}
function oneDaySafe(){let s=sums(); let routine=(state.subs||[]).reduce((a,b)=>a+(+b.amount||0),0); let left=Math.max(0,(s.budget||0)-s.expense-routine); return Math.max(0,left/daysLeft())}
function accountBalance(id){let acc=(state.accounts||[]).find(a=>a.id===id)||{start:0}; let val=+acc.start||0; (state.tx||[]).forEach(t=>{if((t.accountId||'cash')===id){val+=t.type==='income'?(+t.amount||0):-(+t.amount||0)}}); (state.biz||[]).forEach(b=>{if(id==='bisnis')val+=b.type==='in'?(+b.amount||0):-(+b.amount||0)}); return val}
function ensureAccounts(){state.accounts=state.accounts&&state.accounts.length?state.accounts:def.accounts.map(a=>({...a}))}
function applyRules(low, result){let out={...result,rule:null}; (state.rules||[]).forEach(r=>{if(!r||!r.text)return; if(low.includes(String(r.text).toLowerCase())){out.rule=r; if(r.action==='cat'&&r.cat){let c=cats.find(x=>x.id===r.cat); if(c){out.cat=c.id; out.type=c.type}}}}); return out}
function renderWallets(){ensureAccounts(); let html=state.accounts.map(a=>`<div class="item"><div class="row"><h3>👛 ${a.name}</h3><b>${money(accountBalance(a.id))}</b></div><p>Saldo awal ${money(a.start||0)}</p></div>`).join(''); if($('#walletList'))$('#walletList').innerHTML=html; if($('#walletMini'))$('#walletMini').innerHTML=state.accounts.slice(0,4).map(a=>`<div class="kpi"><span>${a.name}</span><strong>${money(accountBalance(a.id))}</strong></div>`).join('')}
function saveWallet(){let name=$('#walletName').value.trim(); if(!name)return toast('Nama dompet kosong'); state.accounts.push({id:'w'+Date.now().toString(36),name,start:num($('#walletStart').value)||0}); $('#walletName').value=''; $('#walletStart').value=''; save('Dompet ditambah'); renderWallets(); fill()}
function renderRules(){let list=state.rules||[]; if($('#rulesList'))$('#rulesList').innerHTML=list.length?list.map((r,i)=>`<div class="item"><div class="row"><h3>Jika: ${r.text}</h3><button class="chip" data-del-rule="${i}">hapus</button></div><p>Aksi: ${r.action}${r.cat?' · '+cat(r.cat).name:''}</p></div>`).join(''):'<p class="helper">Belum ada rules. Contoh: teks berisi ads → masuk Bisnisku.</p>'}
function saveRule(){let text=$('#ruleText').value.trim().toLowerCase(); if(!text)return toast('Isi kata kunci dulu'); let action=$('#ruleAction').value, catid=$('#ruleCat').value; state.rules=state.rules||[]; state.rules.unshift({text,action,cat:catid}); $('#ruleText').value=''; save('Rule disimpan'); renderRules()}
function openBuyCheck(){let p=parseQuick(), amt=num($('#qAmount').value)||p.amount; if(!amt)return toast('Isi transaksi dulu'); let c=cat($('#qCat').value||p.cat), s=sums(), limit=+state.budget[c.id]||0, used=bUsed(c.id), pct=limit?Math.round((used+amt)/limit*100):0, safe=oneDaySafe(), after=Math.max(0,safe-amt); let status=pct>100?'Melewati budget':pct>85?'Masih bisa, tapi ketat':'Masih aman'; $('#buyCheckDetail').innerHTML=`<div class="item"><div class="row"><h3>${c.icon} ${c.name}</h3><b class="${pct>100?'bad':pct>85?'warn':'good'}">${pct}%</b></div><p>Kalau beli ini: ${money(amt)}. Status: ${status}.</p><div class="progress"><div class="bar" style="width:${Math.min(pct,100)}%"></div></div></div><div class="item"><div class="row"><h3>Sisa aman hari ini</h3><b>${money(after)}</b></div><p>Sebelum transaksi ${money(safe)}.</p></div>`; openSheet('buyCheckSheet')}
function miniCalendar(){let mi=monthInfo(), daily=sums().budget?Math.round(sums().budget/mi.dim):0, html=''; for(let d=1; d<=mi.day; d++){let v=txDateAmount(state.month+'-'+String(d).padStart(2,'0')); let cls=!v||!daily||v<=daily*.7?'goodbg':v<=daily?'warnbg':'badbg'; html+=`<span class="dotday ${cls}" title="${d}"></span>`} return html}
function weeklyReviewText(){let s=sums(), week=weekExpense(), target=s.budget?Math.round(s.budget/4.3):0; if(!target)return 'Buat Budgetku dulu agar review mingguan lebih akurat.'; if(week>target)return `Minggu ini lebih tinggi ${money(week-target)} dari target. Coba tahan pengeluaran fleksibel.`; return `Minggu ini masih aman. Sisa ruang minggu ini ${money(target-week)}.`}
function adsRoi(){let arr=(state.biz||[]).filter(thisMonth), income=arr.filter(b=>b.type==='in').reduce((a,b)=>a+(+b.amount||0),0), ads=arr.filter(b=>b.type==='out'&&b.cat==='ads').reduce((a,b)=>a+(+b.amount||0),0), profit=income-arr.filter(b=>b.type==='out').reduce((a,b)=>a+(+b.amount||0),0); return {income,ads,profit,roas:ads?income/ads:0}}
function bizRows(){let rows=[['tanggal','tipe','kategori','deskripsi','nominal']]; (state.biz||[]).filter(thisMonth).forEach(b=>rows.push([b.date,b.type,b.cat,b.desc,b.amount])); (state.products||[]).forEach(p=>rows.push([p.date||today(),'produk','profit',p.name,productProfit(p)])); return rows}
function exportBizExcel(){download('duitly-bisnis.xls','<table>'+bizRows().map(r=>'<tr>'+r.map(c=>'<td>'+c+'</td>').join('')+'</tr>').join('')+'</table>','application/vnd.ms-excel')}
function exportBizPdf(){let r=adsRoi(); let txt=`Duitly Laporan Bisnis\n\nPendapatan: ${rawMoney(r.income)}\nAds: ${rawMoney(r.ads)}\nROAS: ${r.roas.toFixed(2)}x\nProfit: ${rawMoney(r.profit)}\n\nProduk:\n`+(state.products||[]).map(p=>`${p.name} profit ${rawMoney(productProfit(p))} stok ${p.stock||0}`).join('\n'); downloadPdfText('duitly-bisnis.pdf',txt)}
function downloadPdfText(filename,txt){let esc=txt.replace(/[()\\]/g,'\\$&').split('\n'); let y=790,lines='BT /F1 12 Tf 40 '+y+' Td '; esc.forEach((l,i)=>{if(i)lines+='0 -16 Td '; lines+='('+l.slice(0,86)+') Tj ';}); lines+='ET'; let objs=['<< /Type /Catalog /Pages 2 0 R >>','<< /Type /Pages /Kids [3 0 R] /Count 1 >>','<< /Type /Page /Parent 2 0 R /MediaBox [0 0 595 842] /Resources << /Font << /F1 4 0 R >> >> /Contents 5 0 R >>','<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>','<< /Length '+lines.length+' >>\nstream\n'+lines+'\nendstream']; let pdf='%PDF-1.4\n',offs=[0]; objs.forEach((o,i)=>{offs.push(pdf.length); pdf+=(i+1)+' 0 obj\n'+o+'\nendobj\n'}); let xref=pdf.length; pdf+='xref\n0 '+(objs.length+1)+'\n0000000000 65535 f \n'+offs.slice(1).map(o=>String(o).padStart(10,'0')+' 00000 n ').join('\n')+'\ntrailer << /Size '+(objs.length+1)+' /Root 1 0 R >>\nstartxref\n'+xref+'\n%%EOF'; download(filename,pdf,'application/pdf')}
function renderBackupReminder(){let el=$('#backupReminder'); if(!el)return; let last=state.lastBackup?new Date(state.lastBackup):null, days=last?Math.floor((Date.now()-last.getTime())/86400000):999; el.innerHTML=`<div class="row"><h3>${days>6?'Backup disarankan':'Backup aman'}</h3><b>${days>6?'⚠️':'✓'}</b></div><p>${last?'Terakhir backup '+last.toLocaleDateString('id-ID'):'Belum pernah backup. Salin backup supaya data aman.'}</p>`}

function cat(id){return cats.find(c=>c.id===id)||cats.find(c=>c.id==='lainnya')}
function fill(){ensureAccounts(); let qType=$('#qType').value||'expense', oldCat=$('#qCat')?$('#qCat').value:'', oldWallet=$('#qWallet')?$('#qWallet').value:''; $('#qCat').innerHTML=cats.filter(c=>c.type===qType).map(c=>`<option value="${c.id}">${c.icon} ${c.name}</option>`).join(''); if(oldCat&&cats.some(c=>c.id===oldCat&&c.type===qType))$('#qCat').value=oldCat; $('#budgetCat').innerHTML=cats.filter(c=>c.type==='expense').map(c=>`<option value="${c.id}">${c.icon} ${c.name}</option>`).join(''); if($('#qWallet')){$('#qWallet').innerHTML=state.accounts.map(a=>`<option value="${a.id}">${a.name}</option>`).join(''); if(oldWallet)$('#qWallet').value=oldWallet} if($('#ruleCat'))$('#ruleCat').innerHTML=cats.map(c=>`<option value="${c.id}">${c.icon} ${c.name}</option>`).join('')}
function parseQuick(){let raw=$('#quickText').value.trim(),low=raw.toLowerCase(),amount=0,amtTok=''; for(const w of low.split(/\s+/)){let n=num(w); if(n){amount=n; amtTok=w; break}} let type=/gaji|bonus|thr|affiliate|komisi|refund|cashback|dapet|dapat|masuk|income/.test(low)?'income':'expense'; let list=cats.filter(c=>c.type===type); let chosen=state.learn[low.replace(/\d.*$/,'').trim()]||''; let c=list.find(x=>x.id===chosen)||list.find(c=>c.keys.some(k=>low.includes(k)))||list[list.length-1]; let method=/qris|qr/.test(low)?'QRIS':/ewallet|e-wallet|gopay|ovo|dana|spay/.test(low)?'E-Wallet':/transfer|bank|tf/.test(low)?'Transfer':/debit/.test(low)?'Debit':/kredit|cc/.test(low)?'Kredit':'Cash'; let desc=low.split(/\s+/).filter(w=>w!==amtTok&&!/qris|qr|cash|ewallet|e-wallet|gopay|ovo|dana|spay|transfer|bank|tf|debit|kredit|cc/.test(w)).join(' ')||raw||'transaksi'; let first=desc.split(/\s+/)[0]; let pat=state.patterns&&state.patterns[first]; if(pat&&!amtTok&&pat.amounts&&pat.amounts.length){amount=Math.round(pat.amounts.reduce((a,b)=>a+b,0)/pat.amounts.length); method=pat.method||method; c=cats.find(x=>x.id===pat.categoryId)||c} let res=applyRules(low,{raw,type,cat:c.id,amount,method,desc,confidence:raw?(amount?86:50):0}); return res}
function preview(){let p=parseQuick(); $('#confidence').textContent=p.confidence+'%'; $('#qType').value=p.type; fill(); $('#qCat').value=p.cat; $('#qAmount').value=p.amount?String(p.amount):''; $('#qMethod').value=p.method; $('#quickWhy').textContent=p.raw?(p.rule?'rule aktif':(isBizText(p.raw.toLowerCase())?'kemungkinan bisnis':('terdeteksi: '+cat(p.cat).name))):'Siap deteksi'}
function saveQuick(){let p=parseQuick(); let amt=num($('#qAmount').value)||p.amount; if(!amt)return toast('Nominal belum kebaca'); let type=$('#qType').value, categoryId=$('#qCat').value, desc=p.desc, low=(p.raw||desc).toLowerCase();
  if(p.rule&&p.rule.action==='biz'){saveBizTx(desc,amt,'out'); $('#quickText').value=''; preview(); save('Masuk ke Bisnisku'); return}
  // rule 'confirm' tidak memblokir penyimpanan di WebView
  if(type==='expense'&&isBizText(low)&&confirm('Ini terlihat seperti transaksi bisnis. Pindahkan ke Bisnisku?')){saveBizTx(desc,amt,'out'); $('#quickText').value=''; preview(); save('Masuk ke Bisnisku'); return}
  let limit=+state.budget[categoryId]||0, used=bUsed(categoryId), pct=limit?((used+amt)/limit*100):0;
  let overBudget=(type==='expense'&&limit&&pct>=90);
  let tx={id:Date.now().toString(36),date:today(),type,categoryId,amount:amt,method:$('#qMethod').value,accountId:$('#qWallet')?$('#qWallet').value:'cash',desc}; state.tx.unshift(tx); state.lastUndo={kind:'tx',item:tx}; rememberPattern(desc,categoryId,amt,$('#qMethod').value); detectSubscription(tx); $('#quickText').value=''; preview(); save(overBudget?(cat(categoryId).name+' '+Math.round(pct)+'% budget — tetap dicatat ⚠️'):'Tersimpan')}
function rememberPattern(desc,categoryId,amount,method){let key=String(desc||'').split(/\s+/)[0]; if(!key||key.length<3)return; state.patterns=state.patterns||{}; let p=state.patterns[key]||{count:0,amounts:[],categoryId,method}; p.count++; p.categoryId=categoryId; p.method=method; p.amounts=(p.amounts||[]).concat([amount]).slice(-8); state.patterns[key]=p}
function undoLast(){let u=state.lastUndo; if(!u)return toast('Belum ada yang bisa di-undo'); if(u.kind==='tx')state.tx=state.tx.filter(t=>t.id!==u.item.id); if(u.kind==='biz')state.biz=state.biz.filter(t=>t.id!==u.item.id); state.lastUndo=null; save('Undo selesai')}
function sums(){let tx=state.tx.filter(thisMonth),income=0,expense=0; tx.forEach(t=>{if(t.type==='income')income+=+t.amount||0; else expense+=+t.amount||0}); let b=Object.values(state.budget||{}).reduce((a,b)=>a+(+b||0),0); return {tx,income,expense,net:income-expense,budget:b,used:b?Math.min(999,expense/b*100):0}}
function bUsed(id){return state.tx.filter(t=>thisMonth(t)&&t.type==='expense'&&t.categoryId===id).reduce((a,b)=>a+(+b.amount||0),0)}
function budgetScore(){let s=sums(); if(!s.budget)return 0; return Math.max(0,Math.round(100-Math.max(0,s.used-75)*2))}
function setBudget(){let base=num($('#incomeBase').value)||sums().income||7000000; let style=$('#budgetStyle').value; let pct={balanced:{makan:.22,transport:.12,tagihan:.18,belanja:.15,sehat:.07,hiburan:.08,invest:.10,lainnya:.08},hemat:{makan:.18,transport:.10,tagihan:.20,belanja:.12,sehat:.07,hiburan:.04,invest:.20,lainnya:.09},invest:{makan:.18,transport:.10,tagihan:.16,belanja:.10,sehat:.06,hiburan:.05,invest:.27,lainnya:.08},debt:{makan:.18,transport:.10,tagihan:.17,belanja:.10,sehat:.05,hiburan:.03,invest:.07,lainnya:.30},freelance:{makan:.20,transport:.08,tagihan:.18,belanja:.10,sehat:.08,hiburan:.06,invest:.15,lainnya:.15}}[style]; Object.keys(pct).forEach(k=>state.budget[k]=Math.round(base*pct[k]/10000)*10000); $('#budgetStatus').textContent='Aktif dari acuan '+compact(base); save('Budget aktif')}
function renderBudget(){let score=budgetScore(); $('#budgetScore').textContent=score+'%'; $('#budgetScoreBar').style.width=score+'%'; let keys=Object.keys(state.budget||{}); $('#budgetStatus').textContent=keys.length?`Aktif ${compact(Object.values(state.budget).reduce((a,b)=>a+b,0))} · ${keys.length} kategori`:'Belum ada budget aktif.'; let mini=keys.slice(0,3).map(id=>{let limit=state.budget[id]||0,u=bUsed(id),p=limit?Math.round(u/limit*100):0,c=cat(id);return `<div class="item"><div class="row"><h3>${c.icon} ${c.name}</h3><b>${p}%</b></div><p>${money(u)} / ${money(limit)}</p><div class="progress"><div class="bar" style="width:${Math.min(p,100)}%"></div></div></div>`}).join(''); $('#budgetMini').innerHTML=mini||'<div class="helper" style="margin-top:10px">Pakai Auto dulu, nanti progress muncul di sini.</div>'; $('#budgetDetail').innerHTML=(keys.map(id=>{let limit=state.budget[id]||0,u=bUsed(id),p=limit?Math.round(u/limit*100):0,c=cat(id);return `<div class="item" data-budget-edit="${id}"><div class="row"><h3>${c.icon} ${c.name}</h3><b>${p}%</b></div><p>${money(u)} / ${money(limit)} · sisa ${money(Math.max(0,limit-u))}</p><div class="progress"><div class="bar" style="width:${Math.min(p,100)}%"></div></div></div>`}).join('')||'<p class="helper">Belum ada KPI Budget.</p>')}
function parseBiz(){let raw=$('#bizText').value.trim(),low=raw.toLowerCase(),amount=0; for(const w of low.split(/\s+/)){let n=num(w); if(n){amount=n;break}} let type=/affiliate|komisi|jualan|order|masuk|pendapatan|income/.test(low)?'in':'out'; let cat=type==='in'?'lain':'lain'; if(/affiliate|komisi/.test(low))cat='affiliate'; if(/jualan|order/.test(low))cat='jualan'; if(/supplier|stok|modal|barang/.test(low))cat='supplier'; if(/iklan|ads|tiktok|meta|facebook/.test(low))cat='ads'; if(/pack|bubble|dus|plastik/.test(low))cat='pack'; if(/ongkir|kurir/.test(low))cat='ship'; if(/fee|admin|marketplace/.test(low))cat='fee'; if(/tools|aplikasi|canva/.test(low))cat='tools'; let desc=low.replace(/rp/g,'').replace(/\d+[\w.,]*/,'').trim()||raw||'bisnis'; return {raw,type,cat,amount,desc}}
function saveBiz(){let p=parseBiz(); if(!p.amount)return toast('Nominal bisnis belum kebaca'); state.biz.unshift({id:Date.now().toString(36),date:today(),...p}); $('#bizText').value=''; save('Bisnis tersimpan')}
function renderBiz(){let arr=(state.biz||[]).filter(thisMonth),inn=0,out=0; arr.forEach(b=>b.type==='in'?inn+=b.amount:out+=b.amount); $('#bizIn').textContent=money(inn); $('#bizOut').textContent=money(out); $('#bizNet').textContent=money(inn-out); $('#bizNet').className=inn-out>=0?'good':'bad'; let roi=adsRoi(); let html=arr.slice(0,3).map(b=>`<div class="item"><h3>${b.type==='in'?'📥':'📤'} ${b.desc}</h3><p>${b.date} · ${b.cat}</p><b class="${b.type==='in'?'good':'bad'}">${b.type==='in'?'+':'-'}${money(b.amount)}</b></div>`).join(''); $('#bizRecent').innerHTML=(roi.ads?`<div class="item"><div class="row"><h3>ROAS Ads</h3><b>${roi.roas.toFixed(2)}x</b></div><p>Ads ${money(roi.ads)} · pendapatan ${money(roi.income)} · profit ${money(roi.profit)}</p></div>`:'')+(html||'<p class="helper" style="margin-top:10px">Belum ada cashflow bisnis.</p>'); $('#bizDetail').innerHTML=(arr.map(b=>`<div class="item"><div class="row"><h3>${b.type==='in'?'📥':'📤'} ${b.desc}</h3><button class="chip" data-del-biz="${b.id}">hapus</button></div><p>${b.date} · ${b.cat}</p><b class="${b.type==='in'?'good':'bad'}">${b.type==='in'?'+':'-'}${money(b.amount)}</b></div>`).join('')||'<p class="helper">Belum ada data bisnis.</p>')}
function renderRecent(){let h=state.tx.filter(thisMonth); const card=t=>{let c=cat(t.categoryId);return `<div class="item"><div class="row"><h3>${c.icon} ${t.desc}</h3><span style="display:flex;gap:6px"><button class="chip" data-edit="${t.id}">edit</button><button class="chip" data-del="${t.id}">hapus</button></span></div><p>${t.date} · ${c.name} · ${t.method}</p><b class="${t.type==='income'?'good':'bad'}">${t.type==='income'?'+':'-'}${money(t.amount)}</b></div>`}; $('#recentMini').innerHTML=h.slice(0,2).map(card).join('')||'<p class="helper">Belum ada transaksi.</p>'; $('#recentDetail').innerHTML=h.map(card).join('')||'<p class="helper">Belum ada transaksi.</p>'; let q=(window.__histQ||'').toLowerCase(); let hist=q?h.filter(t=>((t.desc||'')+' '+cat(t.categoryId).name+' '+(t.method||'')).toLowerCase().includes(q)):h; $('#historyList').innerHTML=hist.map(card).join('')||'<p class="helper">'+(q?'Tidak ada transaksi yang cocok.':'Belum ada transaksi bulan ini.')+'</p>'}
function monthInfo(){let [y,m]=state.month.split('-').map(Number),dim=new Date(y,m,0).getDate(),now=new Date(),isNow=state.month===now.toISOString().slice(0,7),day=isNow?now.getDate():dim; return {y,m,dim,day,isNow}}
function weekRange(mi){let d=new Date(mi.y,mi.m-1,mi.day),dow=(d.getDay()+6)%7,start=Math.max(1,mi.day-dow),end=Math.min(mi.dim,start+6); return {start,end,days:end-start+1}}
function spentBetween(start,end){return state.tx.filter(thisMonth).reduce((sum,t)=>{let d=Number((t.date||'').slice(8,10)); return t.type==='expense'&&d>=start&&d<=end?sum+(+t.amount||0):sum},0)}
function targetCard(title,used,total,sub){let pct=total?Math.min(999,used/total*100):0; let status=pct>100?'bad':pct>85?'warn':'good'; return `<div class="item"><div class="row"><h3>${title}</h3><b class="${status}">${Math.round(pct)}%</b></div><p>${money(used)} / ${money(total)}${sub?' · '+sub:''}</p><div class="progress"><div class="bar" style="width:${Math.min(pct,100)}%"></div></div></div>`}
function countNoSpendDays(){let mi=monthInfo(),count=0; for(let d=1; d<=mi.day; d++){let ds=state.month+'-'+String(d).padStart(2,'0'); if(txDateAmount(ds)===0)count++} return count}
function monthColorSummary(){let mi=monthInfo(),daily=sums().budget?Math.round(sums().budget/mi.dim):0,green=0,yellow=0,red=0; for(let d=1; d<=mi.day; d++){let ds=state.month+'-'+String(d).padStart(2,'0'),v=txDateAmount(ds); if(!v||!daily||v<=daily*.7)green++; else if(v<=daily)yellow++; else red++} return {green,yellow,red}}
function renderInsight(){
  let s=sums(), daily=oneDaySafe(), todayOut=txDateAmount(today(),'expense'), week=weekExpense(), weekTarget=s.budget?Math.round(s.budget/4.3):0, tom=tomorrowForecast(), score=behaviorScore(), colors=monthColorSummary();
  let todayPct=daily?Math.round(todayOut/daily*100):0, weekPct=weekTarget?Math.round(week/weekTarget*100):0;
  let stUse=p=>p>100?'bad':p>85?'warn':'good', stScore=v=>v>=80?'good':v>=60?'warn':'bad';
  let metric=(name,val,vstatus,pct,bstatus,sub)=>`<div class="coach-metric"><div class="coach-metric-head"><span class="coach-metric-name">${name}</span><span class="coach-metric-val ${vstatus}">${val}</span></div><div class="progress"><div class="bar ${bstatus}" style="width:${Math.max(0,Math.min(pct,100))}%"></div></div><div class="coach-metric-sub">${sub}</div></div>`;
  $('#insightBox').innerHTML=`<div class="coach-hero"><div class="coach-hero-top"><span class="coach-hero-label">Aman dipakai hari ini</span><span class="pillmini ${stUse(todayPct)}">${todayPct}% terpakai</span></div><div class="coach-hero-amt">${money(daily)}</div><div class="coach-hero-sub">Sisa setelah budget &amp; biaya rutin.</div><div class="progress"><div class="bar ${stUse(todayPct)}" style="width:${Math.min(todayPct,100)}%"></div></div><div class="coach-hero-foot">Keluar hari ini ${money(todayOut)} dari target ${money(daily)}</div></div>`+
  `<div class="card coach-metrics">`+
  metric('Budget bulan ini',Math.round(s.used)+'%',stUse(s.used),s.used,stUse(s.used),`${money(s.expense)} / ${money(s.budget||0)} · sisa ${money(Math.max(0,(s.budget||0)-s.expense))}`)+
  metric('Minggu ini',weekPct+'%',stUse(weekPct),weekPct,stUse(weekPct),`Keluar ${money(week)} / target ${money(weekTarget)}`)+
  metric('Skor kebiasaan',score+'/100',stScore(score),score,stScore(score),score>=80?'Ritme bagus. Pertahankan.':score>=60?'Masih aman, cek kategori terbesar.':'Perlu rem sedikit minggu ini.')+
  `</div>`+
  `<div class="coach-quick"><div class="kpi"><span>Cashflow besok</span><strong class="${tom.net>0?'good':'warn'}">${money(tom.net)}</strong></div><div class="kpi"><span>Estimasi rutin / hari</span><strong>${money(tom.sub)}</strong></div></div>`;
  $('#weeklyBox').innerHTML=`<div class="item"><h3>Auto review mingguan</h3><p>${weeklyReviewText()}</p></div><div class="item"><div class="row"><h3>Mood bulan ini</h3><b><span class="good">${colors.green}</span> / <span class="warn">${colors.yellow}</span> / <span class="bad">${colors.red}</span></b></div><p>Hijau aman · kuning normal · merah boros.</p><div class="tinycal">${miniCalendar()}</div></div><div class="item"><div class="row"><h3>Langganan</h3><button class="chip" onclick="openSheet('subsSheet')">Lihat</button></div><p>${(state.subs||[]).length} item rutin terdeteksi.</p></div><div class="item pro-only"><div class="row"><h3>Dompet</h3><button class="chip" onclick="openSheet('walletSheet')">Atur</button></div><div class="grid2" id="walletMini"></div></div>`;
  renderWallets();
  $('#coachDetail').innerHTML=$('#insightBox').innerHTML+`<div class="item" style="margin-top:10px"><h3>Budget Assistant</h3><p>${s.used>90?'Kunci pengeluaran fleksibel. Kalau perlu, pakai Budget Lock sebelum simpan.':tom.sub>0?'Ada biaya rutin terdeteksi. Sisihkan sebelum belanja harian.':'Belum ada risiko besar. Cek budget 2-3 hari sekali.'}</p></div>`;
}
function totalBalance(){ensureAccounts();return (state.accounts||[]).reduce((a,acc)=>a+accountBalance(acc.id),0)}
function renderBalanceHero(){let s=sums(),tb=totalBalance(),e; if(e=$('#balTotal'))e.textContent=money(tb); if(e=$('#balIn'))e.textContent=money(s.income); if(e=$('#balOut'))e.textContent=money(s.expense); if(e=$('#balNet')){e.textContent=money(s.net);e.className=s.net>=0?'good':'bad'} if(e=$('#balMonthTag'))e.textContent=monthName(state.month)}
function renderSummary(){let s=sums(),e; if(e=$('#netSum')){e.textContent=money(s.net);e.className=s.net>=0?'good':'bad'} if(e=$('#incomeSum'))e.textContent=money(s.income); if(e=$('#expenseSum'))e.textContent=money(s.expense); if(e=$('#safeToday'))e.textContent=money(oneDaySafe())}
function render(){document.body.dataset.theme=state.theme||'night'; document.body.classList.toggle('simple-mode',!state.proMode); let pb=$('#privacyBtn'); if(pb)pb.textContent=state.privacy?'👁':'🙈'; let tm=$('#toggleMode'); if(tm)tm.textContent=state.proMode?'Pro':'Simple'; renderSummary(); renderBudget(); renderRecent(); renderInsight(); renderBiz(); renderProducts(); renderSubs(); renderWallets(); renderRules(); renderBackupReminder(); renderGoals(); renderMonthNav(); renderBalanceHero()}
function go(id){$$('.section').forEach(s=>s.classList.toggle('active',s.id===id)); $$('[data-go]').forEach(b=>b.classList.toggle('active',b.dataset.go===id)); window.scrollTo({top:0,behavior:'smooth'}); $('#fabCatat').classList.toggle('hide',id==='catat')}
function openSheet(id){$('#'+id).classList.add('show')} function closeSheet(id){$('#'+id).classList.remove('show')}
function csvRows(){let rows=[['tanggal','tipe','kategori','deskripsi','metode','nominal']]; state.tx.filter(thisMonth).forEach(t=>rows.push([t.date,t.type,cat(t.categoryId).name,t.desc,t.method,t.amount])); return rows}
function download(name,content,type){let a=document.createElement('a'),b=new Blob([content],{type}); a.href=URL.createObjectURL(b); a.download=name; a.click(); setTimeout(()=>URL.revokeObjectURL(a.href),1000)}
function exportCsv(){download('duitly-transaksi.csv',csvRows().map(r=>r.map(x=>'"'+String(x).replace(/"/g,'""')+'"').join(',')).join('\n'),'text/csv')}
function exportExcel(){download('duitly-laporan.xls','<table>'+csvRows().map(r=>'<tr>'+r.map(c=>'<td>'+c+'</td>').join('')+'</tr>').join('')+'</table>','application/vnd.ms-excel')}
function makePdfText(){let s=sums();return `Duitly Laporan Bulanan\n\nMasuk: ${rawMoney(s.income)}\nKeluar: ${rawMoney(s.expense)}\nSisa: ${rawMoney(s.net)}\nBudget terpakai: ${Math.round(s.used)}%\n\nTransaksi:\n`+state.tx.filter(thisMonth).map(t=>`${t.date} ${t.type} ${cat(t.categoryId).name} ${t.desc} ${rawMoney(t.amount)}`).join('\n')}
function exportPdf(){let txt=makePdfText(); let esc=txt.replace(/[()\\]/g,'\\$&').split('\n'); let y=790,lines='BT /F1 12 Tf 40 '+y+' Td '; esc.forEach((l,i)=>{if(i)lines+='0 -16 Td '; lines+='('+l.slice(0,86)+') Tj ';}); lines+='ET'; let objs=['<< /Type /Catalog /Pages 2 0 R >>','<< /Type /Pages /Kids [3 0 R] /Count 1 >>','<< /Type /Page /Parent 2 0 R /MediaBox [0 0 595 842] /Resources << /Font << /F1 4 0 R >> >> /Contents 5 0 R >>','<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>','<< /Length '+lines.length+' >>\nstream\n'+lines+'\nendstream']; let pdf='%PDF-1.4\n',offs=[0]; objs.forEach((o,i)=>{offs.push(pdf.length); pdf+=(i+1)+' 0 obj\n'+o+'\nendobj\n'}); let xref=pdf.length; pdf+='xref\n0 '+(objs.length+1)+'\n0000000000 65535 f \n'+offs.slice(1).map(o=>String(o).padStart(10,'0')+' 00000 n ').join('\n')+'\ntrailer << /Size '+(objs.length+1)+' /Root 1 0 R >>\nstartxref\n'+xref+'\n%%EOF'; download('duitly-laporan.pdf',pdf,'application/pdf')}
function backupPayload(){return JSON.stringify({app:'duitly',version:2,createdAt:new Date().toISOString(),state},null,2)}
function copyBackup(){state.lastBackup=new Date().toISOString(); localStorage.setItem(KEY,JSON.stringify(state)); let txt=backupPayload(); if(navigator.clipboard&&navigator.clipboard.writeText){navigator.clipboard.writeText(txt).then(()=>toast('Backup disalin')).catch(()=>{downloadBackup();toast('Clipboard diblokir, file backup dibuat')})}else{downloadBackup();toast('File backup dibuat')}}
function downloadBackup(){state.lastBackup=new Date().toISOString(); localStorage.setItem(KEY,JSON.stringify(state)); download('duitly-backup.json',backupPayload(),'application/json'); renderBackupReminder()}
function restoreData(){try{let raw=$('#restoreText').value.trim(); if(!raw)return toast('Backup masih kosong'); let obj=JSON.parse(raw); let next=obj.state||obj; if(!next||typeof next!=='object')throw Error('format'); state={...def,...next,tx:next.tx||next.transactions||[],biz:next.biz||[],products:next.products||[],subs:next.subs||[],snapshots:next.snapshots||[],budget:next.budget||next.budgets||{},learn:next.learn||{}}; localStorage.setItem(KEY,JSON.stringify(state)); closeSheet('restoreSheet'); render(); toast('Backup dipulihkan')}catch(e){toast('Format backup tidak valid')}}

function rolloverData(){let rows=[],total=0; cats.filter(c=>c.type==='expense').forEach(c=>{let limit=+state.budget[c.id]||0, used=bUsed(c.id), left=Math.max(0,limit-used); if(left>0){rows.push({id:c.id,name:c.name,icon:c.icon,left}); total+=left}}); return {rows,total}}
function renderRollover(){let r=rolloverData(); $('#rolloverDetail').innerHTML=r.rows.length?`<div class="item"><div class="row"><h3>Sisa bisa dipindah</h3><b>${money(r.total)}</b></div><p>Pilihan aman: pindahkan ke Investasi agar tidak terasa hangus.</p></div>`+r.rows.slice(0,8).map(x=>`<div class="item"><div class="row"><h3>${x.icon} ${x.name}</h3><b>${money(x.left)}</b></div></div>`).join(''):'<div class="item"><h3>Belum ada sisa</h3><p>Tidak ada budget positif yang bisa di-rollover.</p></div>'}
function applyRollover(){let r=rolloverData(); if(!r.total)return toast('Belum ada sisa'); state.budget.invest=(+state.budget.invest||0)+r.total; save('Sisa masuk Investasi'); renderRollover()}
function renderMonthSummary(){let s=sums(), colors=monthColorSummary(), noSpend=countNoSpendDays(), top={name:'-',v:0}; cats.filter(c=>c.type==='expense').forEach(c=>{let u=bUsed(c.id); if(u>top.v)top={name:c.name,v:u}}); $('#monthSummaryDetail').innerHTML=`<div class="item"><div class="row"><h3>Bulan ini</h3><b>${Math.round(s.used)}%</b></div><p>Masuk ${money(s.income)} · keluar ${money(s.expense)} · sisa ${money(s.net)}</p><div class="progress"><div class="bar" style="width:${Math.min(s.used,100)}%"></div></div></div><div class="item"><h3>Highlight</h3><p>Kategori terbesar: ${top.name} ${money(top.v)}.</p><p>Hari hemat ${colors.green}, normal ${colors.yellow}, boros ${colors.red}. No spend ${noSpend}/8.</p></div><div class="item"><h3>Saran bulan depan</h3><p>${s.used>100?'Turunkan kategori terbesar 10-15% dan kunci belanja fleksibel.':'Pertahankan ritme. Sisihkan sisa budget ke target tabungan/investasi.'}</p></div>`}

function openEditTx(id){let t=state.tx.find(x=>x.id===id); if(!t)return toast('Transaksi tidak ada'); window.__editId=id; $('#editType').value=t.type; fillEditCat(); $('#editCat').value=t.categoryId; $('#editDesc').value=t.desc||''; $('#editAmount').value=t.amount?String(t.amount):''; $('#editMethod').value=t.method||'Cash'; $('#editDate').value=(t.date||today()).slice(0,10); openSheet('editTxSheet')}
function fillEditCat(){let ty=$('#editType').value; $('#editCat').innerHTML=cats.filter(c=>c.type===ty).map(c=>`<option value="${c.id}">${c.icon} ${c.name}</option>`).join('')}
function saveEditTx(){let id=window.__editId; let t=state.tx.find(x=>x.id===id); if(!t)return toast('Transaksi tidak ada'); let amt=num($('#editAmount').value); if(!amt)return toast('Nominal belum kebaca'); t.type=$('#editType').value; t.categoryId=$('#editCat').value; let d=$('#editDesc').value.trim(); if(d)t.desc=d; t.amount=amt; t.method=$('#editMethod').value; let dt=$('#editDate').value; if(dt)t.date=dt; closeSheet('editTxSheet'); save('Transaksi diperbarui')}
function persistRender(){try{localStorage.setItem(KEY,JSON.stringify(state))}catch(e){} render()}
function monthName(ym){let a=String(ym||'').split('-').map(Number); if(a.length<2||!a[0])return 'bulan ini'; return new Date(a[0],a[1]-1,1).toLocaleDateString('id-ID',{month:'long',year:'numeric'})}
function monthShift(delta){let a=state.month.split('-').map(Number); let d=new Date(a[0],(a[1]-1)+delta,1); state.month=d.toISOString().slice(0,7); window.__histQ=''; let hs=$('#histSearch'); if(hs)hs.value=''; persistRender(); toast(monthName(state.month))}
function renderMonthNav(){let el=$('#histMonthLabel'); if(el){let nowM=new Date().toISOString().slice(0,7); el.textContent=monthName(state.month)+(state.month===nowM?' · bulan ini':'')} let s=sums(); if($('#histIncome'))$('#histIncome').textContent=money(s.income); if($('#histExpense'))$('#histExpense').textContent=money(s.expense)}
function renderGoals(){let g=state.goals||[]; let pct=x=>x.target?Math.min(100,Math.round((+x.saved||0)/x.target*100)):0; let mini=g.slice(0,2).map(x=>`<div class="item"><div class="row"><h3>🎯 ${x.name}</h3><b>${pct(x)}%</b></div><p>${money(x.saved)} / ${money(x.target)}</p><div class="progress"><div class="bar" style="width:${pct(x)}%"></div></div></div>`).join(''); if($('#goalsMini'))$('#goalsMini').innerHTML=mini||'<p class="helper" style="margin-top:10px">Belum ada target. Buat target tabungan pertamamu.</p>'; if($('#goalsList'))$('#goalsList').innerHTML=g.length?g.map((x,i)=>`<div class="item"><div class="row"><h3>🎯 ${x.name}</h3><button class="chip" data-del-goal="${i}">hapus</button></div><p>${money(x.saved)} / ${money(x.target)} · ${pct(x)}% · sisa ${money(Math.max(0,(x.target||0)-(+x.saved||0)))}</p><div class="progress"><div class="bar" style="width:${pct(x)}%"></div></div><div class="grid2" style="margin-top:8px"><input class="goal-add" data-gi="${i}" placeholder="+ setor (mis. 100rb)"><button class="chip goal-add-btn" data-gi="${i}">Setor</button></div></div>`).join(''):'<p class="helper" style="margin-top:10px">Belum ada target tabungan.</p>'}
function saveGoal(){let name=$('#goalName').value.trim(); if(!name)return toast('Nama target kosong'); let target=num($('#goalTarget').value), saved=num($('#goalSaved').value); if(!target)return toast('Isi target dana'); state.goals=state.goals||[]; state.goals.unshift({id:Date.now().toString(36),name,target,saved,date:today()}); $('#goalName').value='';$('#goalTarget').value='';$('#goalSaved').value=''; save('Target ditambah'); renderGoals()}
function init(){fill(); $('#qType').onchange=()=>{fill();preview()}; $('#quickText').oninput=preview; $('#quickText').onkeydown=e=>{if(e.key==='Enter')saveQuick()}; $('#quickText').onfocus=()=>document.body.classList.add('soft-kbd'); $('#quickText').onblur=()=>document.body.classList.remove('soft-kbd'); $('#saveQuick').onclick=saveQuick; $('#preBuyBtn').onclick=openBuyCheck; $('#buyCheckSave').onclick=()=>{closeSheet('buyCheckSheet');saveQuick()}; $('#openQuickMore').onclick=()=>openSheet('quickSheet'); $('#openSplit').onclick=openSplitSheet; $('#addSplitRow').onclick=()=>addSplitRow(); $('#saveSplit').onclick=saveSplit; $('#openRecent').onclick=()=>openSheet('recentSheet'); $('#openBudgetKpi').onclick=()=>openSheet('budgetKpiSheet'); $('#openManualBudget').onclick=()=>openSheet('manualBudgetSheet'); $('#openBudgetHelp').onclick=()=>{ $('#budgetHelpText').innerHTML='<b>Auto Budget</b><p class="helper">Acuan bulanan dibagi sesuai gaya: Seimbang, Hemat, Investasi, Cicilan, atau Freelance. Semua masih bisa diedit manual.</p>'; openSheet('budgetHelpSheet')}; $('#makeBudget').onclick=setBudget; $('#saveBudget').onclick=()=>{let v=num($('#budgetAmount').value); if(!v)return toast('Nominal belum kebaca'); state.budget[$('#budgetCat').value]=v; closeSheet('manualBudgetSheet'); save('Budget disimpan')}; $('#budgetCat').onchange=()=>$('#budgetAmount').value=state.budget[$('#budgetCat').value]?compact(state.budget[$('#budgetCat').value]):''; $('#saveBiz').onclick=saveBiz; $('#openProductSheet').onclick=()=>openSheet('productSheet'); $('#saveProduct').onclick=saveProduct; $('#bizText').onkeydown=e=>{if(e.key==='Enter')saveBiz()}; $('#openBizDetail').onclick=()=>openSheet('bizSheet'); $('#openCoachDetail').onclick=()=>openSheet('coachSheet'); $('#undoLast').onclick=undoLast; $('#privacyBtn').onclick=()=>{state.privacy=!state.privacy;save(state.privacy?'Mode privasi aktif':'Mode privasi mati')}; $('#openRollover').onclick=()=>{renderRollover();openSheet('rolloverSheet')}; $('#applyRollover').onclick=applyRollover; $('#openMonthSummary').onclick=()=>{renderMonthSummary();openSheet('summarySheet')}; $('#clearFilter').onclick=()=>toast('Menampilkan bulan ini'); $('#themeBtn').onclick=()=>{state.theme=state.theme==='night'?'light':state.theme==='light'?'mint':state.theme==='mint'?'sunset':'night';save('Tema diganti')}; $('#fabCatat').onclick=()=>{go('catat');setTimeout(()=>{let qt=$('#quickText');if(qt)qt.focus()},120)}; $('#exportCsv').onclick=exportCsv; $('#exportExcel').onclick=exportExcel; $('#exportPdf').onclick=exportPdf; $('#exportBizPdf').onclick=exportBizPdf; $('#exportBizExcel').onclick=exportBizExcel; $('#copyBackup').onclick=copyBackup; $('#downloadBackup').onclick=downloadBackup; $('#openRestore').onclick=()=>openSheet('restoreSheet'); $('#restoreSnapshot').onclick=restoreSnapshot; $('#restoreData').onclick=restoreData; $('#openWallets').onclick=()=>{renderWallets();openSheet('walletSheet')}; $('#saveWallet').onclick=saveWallet; $('#openRules').onclick=()=>{renderRules();openSheet('rulesSheet')}; $('#saveRule').onclick=saveRule; $('#toggleMode').onclick=()=>{state.proMode=!state.proMode;save(state.proMode?'Mode Pro aktif':'Mode Simple aktif')}; $('#resetData').onclick=()=>{if(confirm('Reset semua data?')){state=JSON.parse(JSON.stringify(def));save('Reset selesai')}}; $('#learnBtn').onclick=()=>{let p=parseQuick(); let key=p.desc.replace(/\d.*$/,'').trim(); if(key){state.learn[key]=$('#qCat').value; save('Kategori diingat')}}; $('#quickChips').innerHTML=['kopi 25k qris','makan 35rb','bensin 100rb','gaji 7jt transfer','listrik 450k','obat 75rb','netflix 50rb','ads tiktok 100rb'].map(x=>`<button class="chip" data-ex="${x}">${x}</button>`).join(''); document.addEventListener('click',e=>{let g=e.target.closest('[data-go]'); if(g){go(g.dataset.go);vib();return} let c=e.target.closest('[data-close]'); if(c){closeSheet(c.dataset.close);return} if(e.target.classList.contains('sheet')){e.target.classList.remove('show');return} let sr=e.target.closest('.split-remove'); if(sr){sr.closest('.split-row').remove();return} let ex=e.target.closest('[data-ex]'); if(ex){$('#quickText').value=ex.dataset.ex;preview();closeSheet('quickSheet');go('catat');return} let base=e.target.closest('[data-base]'); if(base){$('#incomeBase').value=compact(base.dataset.base);return} let be=e.target.closest('[data-budget-edit]'); if(be){$('#budgetCat').value=be.dataset.budgetEdit;$('#budgetAmount').value=compact(state.budget[be.dataset.budgetEdit]||0);openSheet('manualBudgetSheet');return} let del=e.target.closest('[data-del]'); if(del){state.tx=state.tx.filter(t=>t.id!==del.dataset.del);save('Dihapus');return} let db=e.target.closest('[data-del-biz]'); if(db){state.biz=state.biz.filter(t=>t.id!==db.dataset.delBiz);save('Dihapus');return} let bx=e.target.closest('[data-biz-ex]'); if(bx){$('#bizText').value=bx.dataset.bizEx;return} let dr=e.target.closest('[data-del-rule]'); if(dr){state.rules.splice(+dr.dataset.delRule,1);save('Rule dihapus');renderRules();return} let th=e.target.closest('button[data-theme]'); if(th){state.theme=th.dataset.theme;save('Tema disimpan');return}}); preview(); render()}
window.addEventListener('error',e=>{console.error(e.error||e.message);toast('Ada error kecil, tapi aman')});
