/* ===== PWA: service worker + tombol pasang (v6.6) ===== */
(function(){
  if('serviceWorker' in navigator){window.addEventListener('load',function(){navigator.serviceWorker.register('sw.js').catch(function(){});});}
  var deferred=null;
  function makeBtn(){
    if(document.getElementById('installBtn'))return document.getElementById('installBtn');
    var b=document.createElement('button');b.id='installBtn';b.type='button';
    b.textContent='⬇ Pasang Duitly';
    b.style.cssText='position:fixed;left:50%;transform:translateX(-50%);bottom:calc(var(--nav,66px) + 80px);z-index:95;background:linear-gradient(135deg,#7c5cff,#35c7ff);color:#fff;border:0;border-radius:999px;padding:12px 20px;font-weight:700;font-size:13px;box-shadow:0 12px 30px rgba(0,0,0,.32);cursor:pointer';
    b.onclick=function(){
      if(deferred){deferred.prompt();deferred.userChoice.then(function(){deferred=null;b.remove();});}
      else{alert('Buka menu browser (⋮) → \"Tambahkan ke layar utama / Install app\".');}
    };
    document.body.appendChild(b);return b;
  }
  window.addEventListener('beforeinstallprompt',function(e){e.preventDefault();deferred=e;makeBtn();});
  window.addEventListener('appinstalled',function(){var b=document.getElementById('installBtn');if(b)b.remove();});
  var standalone=window.matchMedia&&window.matchMedia('(display-mode: standalone)').matches;
  if(!standalone){setTimeout(function(){if(!deferred&&!document.getElementById('installBtn')){/* iOS/Safari: tampilkan petunjuk manual */ if(/iphone|ipad|ipod/i.test(navigator.userAgent)){var b=makeBtn();b.textContent='⬇ Cara pasang';}}},2500);}
})();
